parameters.jsCode:
const rawOutput = $input.first().json.output;
try {
  return {
    explanation: rawOutput.explanation,   // ← modifié ici
    selected_items_ids: rawOutput.selected_items_ids, // déjà bon
    comfort_score: rawOutput.comfort_score
  };
} catch (error) {
  return {
    error: "Échec du formatage JSON",
    raw: rawOutput,
    details: error
  };
}

const clothesData = $input.first().json.clothes;
const explanationData = $('Code in JavaScript').first().json.explanation; 
const orderedClothes = $('Code in JavaScript').first().json.selected_items_ids.map(id => 
  clothesData.find(item => item.id === id)
).filter(Boolean);
const result = {
  explanation: explanationData,
  comfort_score: $('Code in JavaScript').first().json.comfort_score,
  selected_items_ids: $('Code in JavaScript').first().json.selected_items_ids,
  clothes: orderedClothes
};
return [result];

